    15	package codegen
    16	
    17	import (
    18		"fmt"
    19		"os"
    20	
    21		yaml "go.yaml.in/yaml/v4"
    22	)
    23	
    24	// Config holds YAML configuration for custom type mappings.
    25	type Config struct {
    26		Tables      []TableConfig `yaml:"tables,omitempty"`
    27		Inflections []Inflection  `yaml:"inflections,omitempty"`
    28	}
    29	
    30	// TableConfig configures code generation for a specific table.
    31	type TableConfig struct {
    32		Name    string         `yaml:"name"`
    33		RowName string         `yaml:"row_name,omitempty"`
    34		Columns []ColumnConfig `yaml:"columns,omitempty"`
    35	}
    36	
    37	// ColumnConfig configures code generation for a specific column.
    38	type ColumnConfig struct {
    39		Name            string   `yaml:"name"`
    40		CustomType      string   `yaml:"custom_type,omitempty"`
    41		Imports         []string `yaml:"imports,omitempty"`
    42		JSONType        string   `yaml:"json_type,omitempty"`
    43		JSONTypeImports []string `yaml:"json_type_imports,omitempty"`
    44	}
    45	
    46	// Inflection defines a custom singular/plural inflection.
    47	type Inflection struct {
    48		Singular string `yaml:"singular"`
    49		Plural   string `yaml:"plural"`
    50	}
    51	
    52	// LoadConfig reads a YAML config file.
    53	func LoadConfig(path string) (*Config, error) {
    54		data, err := os.ReadFile(path)
    55		if err != nil {
    56			return nil, fmt.Errorf("reading config file: %w", err)
    57		}
    58	
    59		var cfg Config
    60		if err := yaml.Load(data, &cfg); err != nil {
    61			return nil, fmt.Errorf("parsing config file: %w", err)
    62		}
    63		if err := cfg.validate(); err != nil {
    64			return nil, err
    65		}
    66	
    67		return &cfg, nil
    68	}
    69	
    70	func (c *Config) validate() error {
    71		for _, table := range c.Tables {
    72			for _, column := range table.Columns {
    73				if column.CustomType != "" && column.JSONType != "" {
    74					return fmt.Errorf("table %q column %q cannot set both custom_type and json_type", table.Name, column.Name)
    75				}
    76				if len(column.JSONTypeImports) > 0 && column.JSONType == "" {
    77					return fmt.Errorf("table %q column %q cannot set json_type_imports without json_type", table.Name, column.Name)
    78				}
    79				if len(column.Imports) > 0 && column.CustomType == "" && column.JSONType == "" {
    80					return fmt.Errorf("table %q column %q cannot set imports without custom_type or json_type", table.Name, column.Name)
    81				}
    82			}
    83		}
    84		return nil
    85	}
