   156	func identifierWords(s string) []string {
   157		if s == "" {
   158			return nil
   159		}
   160	
   161		words := make([]string, 0, 4)
   162		start := 0
   163		for i := 1; i < len(s); i++ {
   164			prev := s[i-1]
   165			curr := s[i]
   166			var next byte
   167			if i+1 < len(s) {
